var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`공짜로는 파리도 안 잡아.`,JPN:`タダじゃハエ退治もしねぇぞ。`,ENG:`I don't even catch flies for free.`,TWN:`I don't even catch flies for free.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`하지만…`,JPN:`だが……`,ENG:`However...`,TWN:`However...`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`여기는 계산이 확실한 것 같더군.`,JPN:`ここはきっちり金を払ってくれるみてぇだな。`,ENG:`This place has a firm reputation for making payments.`,TWN:`This place has a firm reputation for making payments.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`그러니 거추장스러운 종이 쪼가리는 저리 치워 둬.`,JPN:`だから、面倒な紙切れなんかいらねぇ。`,ENG:`So put away that ridiculous piece of paper.`,TWN:`So put away that ridiculous piece of paper.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`정산에서 장난만 안 치면 어떻게든 될 거다.`,JPN:`ごまかしさえしなきゃどうとでもなる。`,ENG:`As long as you don't play tricks with the invoice, it'll be fine.`,TWN:`As long as you don't play tricks with the invoice, it'll be fine.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`…흥. 나도 쓸데없는 소리가 늘었군.`,JPN:`……ふん。柄にもねぇこと言っちまったか。`,ENG:`...Hmph. I've become too talkative.`,TWN:`...Hmph. I've become too talkative.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SOL_COLLABO_NULL_NULL`,text:{KOREA:`네가 그런 멍청한 짓을 할 녀석은 아닌데 말이다.`,JPN:`お前はそんな馬鹿じゃなかったな。`,ENG:`You're not one to do something so stupid anyway.`,TWN:`You're not one to do something so stupid anyway.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SOL_COLLABO_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};